export interface Message {
  role: 'user' | 'model';
  text: string;
}

import { GoogleGenAI } from "@google/genai";

const SYSTEM_INSTRUCTION = `
Eres el Consultor Inteligente de Grupo-AR, una empresa líder en construcción, arquitectura e ingeniería industrial. 
Tu objetivo es ayudar a los clientes potenciales a entender cómo Grupo-AR puede realizar sus proyectos.

Información clave de Grupo-AR:
- Servicios: Diseño arquitectónico, Construcción civil, Mantenimiento industrial, Estructuras metálicas, Ingeniería de detalle.
- Valores: Calidad, Innovación, Seguridad y Cumplimiento de plazos.

Cuando un usuario pregunte por un presupuesto, dales una estimación general basada en estándares del mercado (aclarando que es solo una referencia) y anímalos a contactar directamente al equipo humano.
Responde de manera profesional, técnica pero accesible, y siempre en español.
`;

export async function chatWithGemini(userMessage: string, history: { role: 'user' | 'model', parts: { text: string }[] }[]) {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [
        ...history,
        { role: 'user', parts: [{ text: userMessage }] }
      ],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7,
      },
    });

    return response.text || "Lo siento, tuve un problema procesando tu solicitud. Por favor contacta a soporte.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "En este momento no puedo responder. Por favor, intenta más tarde o usa nuestro formulario de contacto.";
  }
}

